    TOKEN_SPEC = [
        ("WS",       r"\s+"),
        ("LPAREN",   r"\("),
        ("RPAREN",   r"\)"),
        ("COMMA",    r","),
        # Operators (order matters for multi-char)
        ("OP",       r"<=|>=|<>|!=|==|=|<|>"),
        # Keywords
        ("AND",      r"(?i)\bAND\b"),
        ("OR",       r"(?i)\bOR\b"),
        ("NOT",      r"(?i)\bNOT\b"),
        ("IN",       r"(?i)\bIN\b"),
        ("LIKE",     r"(?i)\bLIKE\b"),
        ("IS",       r"(?i)\bIS\b"),
        ("TRUE",     r"(?i)\bTRUE\b"),
        ("FALSE",    r"(?i)\bFALSE\b"),
        ("NULL",     r"(?i)\bNULL\b"),
        # Literals
        ("NUMBER",   r"\b\d+\.\d+\b|\b\d+\b"),
        ("DQSTRING", r"\"([^\"\\]|\\.)*\""),
        ("SQSTRING", r"'([^'\\]|\\.)*'"),
        # Identifier (allow dot for nested keys)
        ("IDENT",    r"[A-Za-z_][A-Za-z0-9_\.]*"),
    ]
