            direction = m2.group(2).upper() if m2.group(2) else "ASC"
            order_terms.append((field, direction == "ASC"))

    return {
        "select": select_fields,
        "from": from_raw,
        "where": where_raw.strip() if where_raw else None,
        "order_by": order_terms,
    }


