def _parse_where(tokens, i0=0):
    """
    Parse WHERE into a predicate function.
    Grammar (basic):
      expr := term (OR term)*
      term := factor (AND factor)*
      factor := [NOT] simple
      simple := IDENT ( IN '(' value_list ')' | LIKE value | op value )
    Returns: (predicate_fn, next_index)
    """
