_TOKEN_RE = re.compile(
    r"""
    \s*(?:
        (?P<LPAREN>\() |
        (?P<RPAREN>\)) |
        (?P<OP><=|>=|<>|!=|==|=|<|>) |
        (?P<STRING>'([^'\\]|\\.)*'|"([^"\\]|\\.)*") |
        (?P<NUMBER>\d+\.\d+|\d+) |
        (?P<IDENT>[A-Za-z_][A-Za-z0-9_]*) |
