)

# Operator metadata
_COMPARATORS = {
    "=": operator.eq,
    "==": operator.eq,
    "!=": operator.ne,
    "<>": operator.ne,
    ">": operator.gt,
    ">=": operator.ge,
    "<": operator.lt,
    "<=": operator.le,
}
_BOOL_PRECEDENCE = {
    # higher value = higher precedence
    # Comparators produce predicates; they bind tighter than NOT/AND/OR
    "CMP": 4,       # any comparator
    "NOT": 3,
    "AND": 2,
    "OR": 1,
