        if isinstance(node, ast.BinOp):
            if not is_allowed_operator(node.op):
                return False
            return is_safe_node(node.left) and is_safe_node(node.right)

        # Unary operations
        if isinstance(node, ast.UnaryOp):
            if not is_allowed_unary(node.op):
                return False
