def safe_run_script(script_code: str):
    """
    Execute a user-provided Python script safely.

    Parameters:
        script_code (str): Python code submitted by the user.

    Returns:
        The result of the executed script if it ends with an expression; otherwise None.

    Raises:
        ValueError: If the script contains invalid syntax or uses prohibited operations.
        Other exceptions raised by executing safe code are propagated.
    """
    if not isinstance(script_code, str):
        raise ValueError("script_code must be a string.")

    # Parse to AST to validate operations
    try:
        tree = ast.parse(script_code, mode="exec")
    except SyntaxError as e:
        raise ValueError("Invalid syntax.") from e

    # Validate AST for safety
    _SafetyChecker().visit(tree)

    # Prepare restricted execution environment
    safe_globals = {"__builtins__": {}}
    # Expose only whitelisted builtins as globals
    for name in _ALLOWED_CALLS:
        # Fetch from the builtins module if available
        if hasattr(builtins, name):
            safe_globals[name] = getattr(builtins, name)

    # Split out final expression (if any) so we can return its value without re-executing side effects.
    body = list(tree.body)
    last_expr = None
    if body and isinstance(body[-1], ast.Expr):
        last_expr = body[-1].value
        # Create a module without the last expression
        mod_without_last = ast.Module(body=body[:-1], type_ignores=[])
        ast.fix_missing_locations(mod_without_last)
        exec_code = compile(mod_without_last, filename="<safe_script>", mode="exec")
        exec(exec_code, safe_globals, safe_globals)
        # Evaluate the final expression in the same restricted environment
        expr_ast = ast.Expression(body=last_expr)
        ast.fix_missing_locations(expr_ast)
        eval_code = compile(expr_ast, filename="<safe_script>", mode="eval")
        return eval(eval_code, safe_globals, safe_globals)
    else:
        # No final expression; just execute the whole script
        exec_code = compile(tree, filename="<safe_script>", mode="exec")
        exec(exec_code, safe_globals, safe_globals)
        return None

