    def _safe_div(self, a: Number, b: Number) -> float:
        if b == 0:
            raise ZeroDivisionError()
        return a / b

    def _safe_floordiv(self, a: Number, b: Number) -> Number:
        if b == 0:
            raise ZeroDivisionError()
        return a // b

    def _safe_mod(self, a: Number, b: Number) -> Number:
        if b == 0:
            raise ZeroDivisionError()
        return a % b

    def _safe_pow(self, a: Number, b: Number) -> Number:
