    def _check_float_limits(self, value: float) -> None:
        if math.isnan(value) or math.isinf(value) or abs(value) > _MAX_FLOAT_ABS:
            raise _UnsafeExpression("Float out of bounds")

    def _post_check_number(self, value: Any) -> None:
